export const authRoutes = [
  {
    path: 'login',
    loadComponent: () => import('./login.page')
      .then((m) => m.LoginPage),
  },
];

@Component({
  selector: 'app-login-form',
  templateUrl: './login-form.component.html',
})
export class LoginFormComponent {
  credentials = signal({ email: '', password: '' });
}

@Injectable()
export class AuthService {
  login(credentials: Credentials) {
    return this.http.post<Session>('/api/login', credentials);
  }
}

@Component({
  selector: 'app-product-card',
  templateUrl: './product-card.component.html',
})
export class ProductCardComponent {
  product = input.required<Product>();
}

export type Product = {
  id: string;
  title: string;
  price: number;
  available: boolean;
};

export class CheckoutStore {
  readonly items = signal<CartItem[]>([]);
  readonly total = computed(() => this.items().reduce((sum, item) => sum + item.price, 0));
}

@Component({
  selector: 'app-button',
  template: '<button class="button"><ng-content /></button>',
})
export class ButtonComponent {}
